import{_ as a}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as t,o as i,c as o,a2 as s}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Auto Tagging","description":"","frontmatter":{},"headers":[],"relativePath":"en/Other/auto-tagging.md","filePath":"en/Other/auto-tagging.md","lastUpdated":1781962217000}'),n={name:"en/Other/auto-tagging.md"};function l(r,e,d,c,p,g){return i(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="auto-tagging" tabindex="-1">Auto Tagging <a class="header-anchor" href="#auto-tagging" aria-label="Permalink to &quot;Auto Tagging&quot;">​</a></h1><p>Auto tagging is configured under:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>It automatically generates image tags, which are useful for search, random image filtering, public gallery filtering, and age-rating access control.</p><h2 id="what-auto-tagging-can-do" tabindex="-1">What Auto Tagging Can Do <a class="header-anchor" href="#what-auto-tagging-can-do" aria-label="Permalink to &quot;What Auto Tagging Can Do&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Generate content tags</td><td>Adds tags for people, scenes, objects, art style, and similar visual content.</td></tr><tr><td>Generate character tags</td><td>Useful for anime images and illustrations.</td></tr><tr><td>Add orientation tags</td><td>Adds <code>landscape</code>, <code>portrait</code>, or <code>square</code>.</td></tr><tr><td>Add image rating</td><td>Saves <code>G/S/Q/E</code> rating results for general, sensitive, questionable, or explicit content.</td></tr><tr><td>Auto-tag on upload</td><td>Newly uploaded images enter the tagging flow automatically.</td></tr><tr><td>Batch tagging</td><td>Adds tags to old images in all folders or selected folders.</td></tr></tbody></table><h2 id="what-you-need-first" tabindex="-1">What You Need First <a class="header-anchor" href="#what-you-need-first" aria-label="Permalink to &quot;What You Need First&quot;">​</a></h2><p>Prepare at least one accessible Hugging Face Space URL.</p><p>The recommended approach is to duplicate SmilingWolf&#39;s <code>wd-tagger</code> Space into your own Hugging Face account:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>You can temporarily use the public Space, but public Spaces are shared by many users and may queue, slow down, or become unavailable. A duplicated Space under your own account is more stable for long-term auto tagging.</p><h2 id="duplicate-smilingwolf-s-space" tabindex="-1">Duplicate SmilingWolf&#39;s Space <a class="header-anchor" href="#duplicate-smilingwolf-s-space" aria-label="Permalink to &quot;Duplicate SmilingWolf&#39;s Space&quot;">​</a></h2><ol><li>Sign in to Hugging Face.</li><li>Open <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>.</li></ol><p><img src="'+a+`" alt="SmilingWolf public Space" loading="lazy"></p><ol start="3"><li>Click the three-dot menu in the upper-right corner.</li><li>Choose <code>Duplicate this Space</code>.</li><li>Keep the default Space name or choose your own name, such as <code>wd-tagger</code>.</li><li>Set visibility to <code>Public</code>. Public Spaces are easier for ImgBed to call.</li><li>Keep the default free hardware at first. Upgrade later only if queueing becomes obvious.</li><li>Create the Space and wait for the build to finish.</li></ol><p>After the build finishes, open your Space page. The URL usually looks like:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>Copy the browser URL and paste it into ImgBed&#39;s <code>Space URLs</code>.</p><h2 id="filling-multiple-space-urls" tabindex="-1">Filling Multiple Space URLs <a class="header-anchor" href="#filling-multiple-space-urls" aria-label="Permalink to &quot;Filling Multiple Space URLs&quot;">​</a></h2><p>Enter one Space URL per line.</p><p>Examples:</p><table tabindex="0"><thead><tr><th>Value</th><th>Description</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>SmilingWolf public Space. Good for temporary testing.</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>A copied Space page URL.</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>Your own duplicated Space page URL.</td></tr></tbody></table><p>You can enter multiple URLs. ImgBed uses multiple Spaces together, which can improve speed.</p><p>If one Space is temporarily unavailable, the others can continue processing.</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>Enter the Space URLs you prepared. Use at least one.</td></tr><tr><td>Target folder</td><td>Leave empty for all folders. Select a folder only when you want to process a specific directory.</td></tr><tr><td>Recognition model</td><td>Keep <code>wd-swinv2-tagger-v3</code> by default.</td></tr><tr><td>General tag threshold</td><td>Default works for most images. Lower values produce more tags; higher values produce fewer tags.</td></tr><tr><td>Character tag threshold</td><td>Default is conservative and helps avoid incorrect character tags.</td></tr><tr><td><code>MCut</code> automatic threshold</td><td>Leave off at first. Turn it on when you want the model to decide tag count automatically.</td></tr><tr><td>Auto-tag on upload</td><td>Turn on if newly uploaded images should automatically get tags.</td></tr><tr><td>Start tagging</td><td>Manually batch-tag old images.</td></tr></tbody></table><h2 id="recommended-starting-values" tabindex="-1">Recommended Starting Values <a class="header-anchor" href="#recommended-starting-values" aria-label="Permalink to &quot;Recommended Starting Values&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommended Value</th></tr></thead><tbody><tr><td>Recognition model</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>General tag threshold</td><td><code>0.35</code></td></tr><tr><td>Character tag threshold</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>Off at first</td></tr><tr><td>Auto-tag on upload</td><td>Enable if needed</td></tr></tbody></table><p>If there are too many tags, raise the general threshold slightly.</p><p>If there are too few tags, lower the general threshold slightly.</p><h2 id="batch-tagging" tabindex="-1">Batch Tagging <a class="header-anchor" href="#batch-tagging" aria-label="Permalink to &quot;Batch Tagging&quot;">​</a></h2><ol><li>Fill in <code>Space URLs</code>.</li><li>Select a target folder.</li><li>Click start tagging.</li><li>Wait for progress to finish.</li></ol><p>If the target folder is empty, ImgBed processes all folders.</p><p>Batch tagging is best for old images. For new images, enable auto-tag on upload so you do not need to run it manually each time.</p><h2 id="auto-tag-on-upload" tabindex="-1">Auto-Tag on Upload <a class="header-anchor" href="#auto-tag-on-upload" aria-label="Permalink to &quot;Auto-Tag on Upload&quot;">​</a></h2><p>After auto-tag on upload is enabled, newly uploaded images automatically call the configured <code>Space URLs</code>.</p><p>This is suitable for long-term use.</p><p>If your Space is queueing, the upload itself can still finish first, and tagging continues afterward.</p><h2 id="which-images-are-processed" tabindex="-1">Which Images Are Processed <a class="header-anchor" href="#which-images-are-processed" aria-label="Permalink to &quot;Which Images Are Processed&quot;">​</a></h2><p>Auto tagging mainly processes image files.</p><p>Images that already have complete tags, orientation, rating, width, and height are skipped to avoid unnecessary Space calls.</p><p>ImgBed fills only missing information when possible. For example, if only orientation is missing, it tries to add orientation without calling the full content tag flow.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="why-duplicate-my-own-space" tabindex="-1">Why Duplicate My Own Space? <a class="header-anchor" href="#why-duplicate-my-own-space" aria-label="Permalink to &quot;Why Duplicate My Own Space?&quot;">​</a></h3><p>Public Spaces are shared by many users. Your own duplicated Space is mainly used by your ImgBed site, so it is usually faster and more reliable.</p><h3 id="the-space-keeps-starting-up" tabindex="-1">The Space Keeps Starting Up <a class="header-anchor" href="#the-space-keeps-starting-up" aria-label="Permalink to &quot;The Space Keeps Starting Up&quot;">​</a></h3><p>After first creation, or after a long idle period, a Space may need time to start.</p><p>Open your Space page first. After it can recognize an image normally, return to ImgBed and start tagging.</p><h3 id="how-do-i-copy-the-space-url" tabindex="-1">How Do I Copy the Space URL? <a class="header-anchor" href="#how-do-i-copy-the-space-url" aria-label="Permalink to &quot;How Do I Copy the Space URL?&quot;">​</a></h3><p>Open your Hugging Face Space page and copy the browser address.</p><p>Examples:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="can-i-add-multiple-spaces" tabindex="-1">Can I Add Multiple Spaces? <a class="header-anchor" href="#can-i-add-multiple-spaces" aria-label="Permalink to &quot;Can I Add Multiple Spaces?&quot;">​</a></h3><p>Yes. Enter one Space URL per line.</p><p>Multiple Spaces process images together and are useful when you have many images.</p><h3 id="why-are-tags-in-english" tabindex="-1">Why Are Tags in English? <a class="header-anchor" href="#why-are-tags-in-english" aria-label="Permalink to &quot;Why Are Tags in English?&quot;">​</a></h3><p>SmilingWolf models output English tags. This is expected.</p><p>The tags are mainly used for search, filtering, the random image API, and public gallery filters.</p><h3 id="what-are-rating-tags-used-for" tabindex="-1">What Are Rating Tags Used For? <a class="header-anchor" href="#what-are-rating-tags-used-for" aria-label="Permalink to &quot;What Are Rating Tags Used For?&quot;">​</a></h3><p>Rating results work with the access mode in Security Settings.</p><p>For example, when visitor access is limited by age rating, public browsing and random image features filter images according to those rules.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sign in to Hugging Face</span></span>
<span class="line"><span>-&gt; Open SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; Wait for the Space to build</span></span>
<span class="line"><span>-&gt; Copy your Space URL</span></span>
<span class="line"><span>-&gt; Fill Space URLs in ImgBed</span></span>
<span class="line"><span>-&gt; Choose model and thresholds</span></span>
<span class="line"><span>-&gt; Start tagging or enable auto-tag on upload</span></span></code></pre></div>`,63)])])}const f=t(n,[["render",l]]);export{m as __pageData,f as default};
